def parse_startup_nodes(raw: str) -> List[Dict[str, Any]]:
    nodes = []
    for item in raw.split(","):
        item = item.strip()
        if not item:
            continue
        host, port = item.split(":")
        nodes.append({"host": host.strip(), "port": int(port.strip())})
    if not nodes:
        raise ValueError("No Redis cluster startup nodes configured")
    return nodes


